import{_ as r,C as a,o as t,c as i,a2 as o,b as d,w as s,a as l,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const E=JSON.parse('{"title":"Claude Code — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/claude-code/architecture.md","filePath":"research/agents/claude-code/architecture.md"}'),g={name:"research/agents/claude-code/architecture.md"};function u(m,e,p,b,f,C){const n=a("Mermaid");return t(),i("div",null,[e[1]||(e[1]=o('<h1 id="claude-code-—-architecture" tabindex="-1">Claude Code — Architecture <a class="header-anchor" href="#claude-code-—-architecture" aria-label="Permalink to &quot;Claude Code — Architecture&quot;">​</a></h1><blockquote><p>What we know about Claude Code&#39;s architecture based on official documentation, the public npm package, and observable behavior.</p></blockquote><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><h3 id="confirmed-from-npm-package-metadata-and-docs" tabindex="-1">Confirmed (from npm package metadata and docs) <a class="header-anchor" href="#confirmed-from-npm-package-metadata-and-docs" aria-label="Permalink to &quot;Confirmed (from npm package metadata and docs)&quot;">​</a></h3><ul><li><strong>Language</strong>: TypeScript</li><li><strong>Runtime</strong>: Node.js 18+</li><li><strong>TUI Framework</strong>: Ink (React for the terminal) — renders the interactive CLI using React components</li><li><strong>Package</strong>: <code>@anthropic-ai/claude-code</code> on npm</li><li><strong>Distribution</strong>: Native installers (shell script / PowerShell), Homebrew cask, WinGet, npm (deprecated)</li><li><strong>GitHub</strong>: <code>github.com/anthropics/claude-code</code> — hosts plugins, issue tracker, and the npm package (not the full source)</li></ul><h3 id="inferred-from-observable-behavior" tabindex="-1">Inferred from Observable Behavior <a class="header-anchor" href="#inferred-from-observable-behavior" aria-label="Permalink to &quot;Inferred from Observable Behavior&quot;">​</a></h3><ul><li><strong>API Client</strong>: Uses the Anthropic Messages API with tool-use / function-calling</li><li><strong>Streaming</strong>: Likely uses streaming responses (SSE) for real-time token display</li><li><strong>Local Storage</strong>: Conversations stored as JSONL files locally; sessions persist across restarts</li><li><strong>Git Integration</strong>: Shell-out to <code>git</code> CLI for worktrees, diffs, commits</li></ul><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2><p>Claude Code is described in official docs as an <strong>&quot;agentic harness&quot;</strong> around Claude models. The harness provides tools, context management, and the execution environment that turn a language model into a capable coding agent.</p>',9)),(t(),d(h,null,{default:s(()=>[c(n,{id:"mermaid-77",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20UI%5B%22User%20Input%22%5D%0A%20%20%20%20A%5B%22Ink%20TUI%20Layer%3Cbr%2F%3E%E2%80%A2%20React%20component%20tree%3Cbr%2F%3E%E2%80%A2%20Input%20handling%20(Esc%2C%20Shift%2BTab%2C%20Ctrl%2BO)%3Cbr%2F%3E%E2%80%A2%20Diff%20rendering%2C%20spinners%3Cbr%2F%3E%E2%80%A2%20Permission%20prompt%20dialogs%22%5D%0A%20%20%20%20B%5B%22Session%20Manager%3Cbr%2F%3E%E2%80%A2%20Conversation%20history%20(JSONL)%3Cbr%2F%3E%E2%80%A2%20Checkpoint%20%2F%20rewind%20system%3Cbr%2F%3E%E2%80%A2%20Session%20resume%20%2F%20fork%3Cbr%2F%3E%E2%80%A2%20Context%20window%20tracking%22%5D%0A%20%20%20%20C%5B%22Agentic%20Loop%3Cbr%2F%3E%E2%80%A2%20Sends%20messages%20to%20Claude%20API%3Cbr%2F%3E%E2%80%A2%20Receives%20tool_use%20responses%3Cbr%2F%3E%E2%80%A2%20Executes%20tools%20locally%3Cbr%2F%3E%E2%80%A2%20Feeds%20results%20back%20to%20API%3Cbr%2F%3E%E2%80%A2%20Repeats%20until%20task%20complete%22%5D%0A%20%20%20%20D%5B%22Tool%20System%3Cbr%2F%3E%E2%80%A2%20Built-in%20tools%20(Read%2C%20Edit%2C%20Bash%2C%20Grep%2C%20Glob%2C%20WebFetch)%3Cbr%2F%3E%E2%80%A2%20MCP%20tool%20bridge%3Cbr%2F%3E%E2%80%A2%20Sub-agent%20tool%20(Agent)%3Cbr%2F%3E%E2%80%A2%20Permission%20enforcement%20layer%22%5D%0A%20%20%20%20E%5B%22Permission%20%2F%20Safety%20Layer%3Cbr%2F%3E%E2%80%A2%20allow%20%2F%20ask%20%2F%20deny%20rules%3Cbr%2F%3E%E2%80%A2%20Sandbox%20enforcement%20(OS-level)%3Cbr%2F%3E%E2%80%A2%20Hooks%20(PreToolUse%2C%20PostToolUse%2C%20etc.)%3Cbr%2F%3E%E2%80%A2%20Settings%20precedence%20chain%22%5D%0A%0A%20%20%20%20UI%20--%3E%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%20--%3E%20E%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="component-details" tabindex="-1">Component Details <a class="header-anchor" href="#component-details" aria-label="Permalink to &quot;Component Details&quot;">​</a></h2><h3 id="_1-ink-tui-layer" tabindex="-1">1. Ink TUI Layer <a class="header-anchor" href="#_1-ink-tui-layer" aria-label="Permalink to &quot;1. Ink TUI Layer&quot;">​</a></h3><p>Claude Code uses <strong>Ink</strong> — a React renderer for the terminal (built on the <code>ink</code> npm package). This is an unusual architectural choice that means:</p><ul><li>The CLI UI is a React component tree using JSX/TSX</li><li>Components handle input, render diffs/spinners/progress bars, and display permission dialogs</li><li>The spinner shows customizable &quot;action verbs&quot; while Claude works (<code>spinnerVerbs</code> setting)</li><li>Keyboard shortcuts are handled as component events: <ul><li><code>Esc</code> — interrupt current action (context preserved)</li><li><code>Esc + Esc</code> — open rewind menu</li><li><code>Shift+Tab</code> — cycle permission modes (default → acceptEdits → plan)</li><li><code>Ctrl+O</code> — toggle verbose mode (shows extended thinking)</li><li><code>Option+T</code> / <code>Alt+T</code> — toggle thinking mode</li></ul></li><li>Terminal progress bar support for Windows Terminal and iTerm2</li></ul><h3 id="_2-session-management" tabindex="-1">2. Session Management <a class="header-anchor" href="#_2-session-management" aria-label="Permalink to &quot;2. Session Management&quot;">​</a></h3><ul><li><strong>Storage</strong>: Conversations stored as local JSONL files, one per session</li><li><strong>Cleanup</strong>: Configurable via <code>cleanupPeriodDays</code> (default 30 days); setting to 0 disables persistence</li><li><strong>Checkpointing</strong>: File snapshots taken before every edit, enabling rewind to any previous state</li><li><strong>Resume</strong>: <code>--continue</code> (most recent), <code>--resume</code> (picker), <code>--fork-session</code> (branch off)</li><li><strong>Session picker</strong>: Interactive TUI with search, branch filtering, preview, keyboard navigation</li><li><strong>Naming</strong>: <code>/rename</code> for descriptive names; auto-named from plan content</li><li><strong>Session isolation</strong>: Each new session starts with fresh context window — no conversation history carried over (only CLAUDE.md + auto-memory persist)</li><li><strong>Forking</strong>: <code>--fork-session</code> creates a new session ID while preserving conversation up to that point; original session unchanged</li></ul><h3 id="_3-configuration-system-scoped-settings" tabindex="-1">3. Configuration System (Scoped Settings) <a class="header-anchor" href="#_3-configuration-system-scoped-settings" aria-label="Permalink to &quot;3. Configuration System (Scoped Settings)&quot;">​</a></h3><p>Claude Code has a multi-scope configuration system with strict precedence:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Location</th><th>Precedence</th></tr></thead><tbody><tr><td><strong>Managed</strong></td><td>Server-managed / MDM / plist / registry / system <code>managed-settings.json</code></td><td>Highest (cannot be overridden)</td></tr><tr><td><strong>CLI args</strong></td><td><code>--model</code>, <code>--allowedTools</code>, etc.</td><td>Session-level override</td></tr><tr><td><strong>Local</strong></td><td><code>.claude/settings.local.json</code></td><td>Per-project personal (gitignored)</td></tr><tr><td><strong>Project</strong></td><td><code>.claude/settings.json</code></td><td>Shared via git with team</td></tr><tr><td><strong>User</strong></td><td><code>~/.claude/settings.json</code></td><td>Global personal (lowest)</td></tr></tbody></table><p>Settings control: permissions, hooks, environment variables, model selection, MCP servers, attribution, cleanup, output style, language, and more. A <code>$schema</code> reference to <code>json.schemastore.org/claude-code-settings.json</code> provides IDE autocomplete.</p><h3 id="_4-extension-points" tabindex="-1">4. Extension Points <a class="header-anchor" href="#_4-extension-points" aria-label="Permalink to &quot;4. Extension Points&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Extension</th><th>Purpose</th><th>Context Cost</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>Persistent instructions, loaded every session</td><td>Always loaded (keep &lt; 200 lines)</td></tr><tr><td><strong>Auto Memory</strong></td><td>Claude&#39;s self-written notes from corrections</td><td>First 200 lines of MEMORY.md loaded</td></tr><tr><td><strong>Skills</strong></td><td>On-demand knowledge packages (<code>.claude/skills/</code>)</td><td>Loaded only when relevant</td></tr><tr><td><strong>Sub-agents</strong></td><td>Delegated tasks in separate context windows</td><td>Isolated; return summary only</td></tr><tr><td><strong>MCP Servers</strong></td><td>External tool/data integrations via Model Context Protocol</td><td>Tool definitions per request</td></tr><tr><td><strong>Hooks</strong></td><td>Deterministic shell scripts at lifecycle events</td><td>Zero context cost</td></tr><tr><td><strong>Plugins</strong></td><td>Bundles of skills + hooks + agents + MCP</td><td>Varies by components</td></tr></tbody></table><h3 id="_5-execution-environments" tabindex="-1">5. Execution Environments <a class="header-anchor" href="#_5-execution-environments" aria-label="Permalink to &quot;5. Execution Environments&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Environment</th><th>Where Code Runs</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Local</strong></td><td>Your machine</td><td>Default — full access to files, tools, environment</td></tr><tr><td><strong>Cloud</strong></td><td>Anthropic-managed VMs</td><td>Offload tasks, repos not local, parallel work</td></tr><tr><td><strong>Remote Control</strong></td><td>Your machine, controlled from browser</td><td>Use web UI while keeping everything local</td></tr></tbody></table><h2 id="key-architectural-decisions" tabindex="-1">Key Architectural Decisions <a class="header-anchor" href="#key-architectural-decisions" aria-label="Permalink to &quot;Key Architectural Decisions&quot;">​</a></h2><ol><li><p><strong>Harness + Model separation</strong>: Claude Code is the &quot;agentic harness&quot; — it provides tools, context, execution. The model does reasoning. This clean separation allows model swapping (Sonnet ↔ Opus ↔ Haiku) mid-session.</p></li><li><p><strong>React for the terminal</strong>: Using Ink (React) for the TUI is architecturally novel. It enables component-based UI with familiar React patterns but for CLI rendering. This differentiates it from competitors using simpler terminal output.</p></li><li><p><strong>Local-first architecture</strong>: Conversations, checkpoints, memory, and settings are all stored locally. No cloud dependency for session state (the model API is cloud-based, but all state is local).</p></li><li><p><strong>Defense-in-depth for safety</strong>: Three complementary layers — permission rules (allow/ask/deny), OS-level sandboxing (filesystem + network), and hooks (programmatic pre/post-tool checks). Deny rules always win regardless of source.</p></li><li><p><strong>Context as the primary design constraint</strong>: The entire architecture is designed around managing the finite context window. Auto-compaction, sub-agents (separate windows), skills (on-demand loading), concise CLAUDE.md, and <code>/compact</code> all exist because performance degrades as context fills.</p></li><li><p><strong>Tool-use protocol</strong>: Claude Code uses Anthropic&#39;s native tool-use (function-calling) API, not prompt-injection-based tool use. The model receives tool definitions, returns <code>tool_use</code> blocks, the harness executes them, and results go back as <code>tool_result</code> messages.</p></li></ol>',16))])}const y=r(g,[["render",u]]);export{E as __pageData,y as default};
